mapper.select:
select * from teacher_users
where teacher_user_id in

    #{teacherUserId}

select t.*, d.name departmentName from teacher_users t left join department d on t.department_id = d.id


        and t.teacher_user_id like concat('%',#{teacherUserId},'%')


        and t.name like concat('%',#{name},'%')


        and t.gender = #{gender}


        and t.department_id = #{departmentId}


        and t.status = #{status}


        and t.teacher_type = #{teacherType}


order by t.update_time desc
